import { describe, it, expect } from 'vitest';
import {
  ContinuousBatchScheduler,
  type DecodeBatchBinding,
  type BatchSeq,
} from './continuous-batch-scheduler';

const VOCAB = 10;
const STOP = 0;

// Mock native binding: a deterministic "model" where the next token is (input + 1) % VOCAB.
// One-hot logits per lane so argmax recovers the scripted token. Stateless in the input
// token (so the mock needn't model KV), which lets us assert the SCHEDULING — wave sizing,
// per-lane streaming, retirement, and lane RE-USE (via the recorded resetLane calls).
class MockBinding implements DecodeBatchBinding {
  inited = 0;
  steps = 0;
  resets: number[] = [];
  initBatch(n: number): void {
    this.inited = n;
  }
  resetLane(k: number): void {
    this.resets.push(k);
  }
  decodeStepBatch(tokens: Uint32Array): Float32Array {
    this.steps++;
    const out = new Float32Array(tokens.length * VOCAB);
    for (let k = 0; k < tokens.length; k++) {
      out[k * VOCAB + ((tokens[k] + 1) % VOCAB)] = 1.0;
    }
    return out;
  }
}

function argmax(logits: Float32Array, offset: number, vocab: number): number {
  let best = 0;
  let bestVal = logits[offset];
  for (let i = 1; i < vocab; i++) {
    if (logits[offset + i] > bestVal) {
      bestVal = logits[offset + i];
      best = i;
    }
  }
  return best;
}

function seq(id: string, prompt: number[], out: Record<string, number[]>, done: Record<string, string>): BatchSeq {
  out[id] = [];
  return {
    id,
    promptTokens: prompt,
    maxNewTokens: 50,
    sample: (logits, offset, vocab) => argmax(logits, offset, vocab),
    isStop: (t) => t === STOP,
    onToken: (t) => {
      out[id].push(t);
    },
    onDone: (reason) => {
      done[id] = reason;
    },
  };
}

describe('ContinuousBatchScheduler', () => {
  it('runs K divergent sequences in one batched wave, each streaming its own tokens', async () => {
    const binding = new MockBinding();
    const sched = new ContinuousBatchScheduler(binding, VOCAB, 3);
    expect(binding.inited).toBe(3);

    const out: Record<string, number[]> = {};
    const done: Record<string, string> = {};
    // next = input+1 mod 10, stop at 0:
    sched.admit(seq('a', [3], out, done)); // 4,5,6,7,8,9,0
    sched.admit(seq('b', [7], out, done)); // 8,9,0
    sched.admit(seq('c', [1], out, done)); // 2..9,0

    await sched.run();

    expect(out.a).toEqual([4, 5, 6, 7, 8, 9, 0]);
    expect(out.b).toEqual([8, 9, 0]);
    expect(out.c).toEqual([2, 3, 4, 5, 6, 7, 8, 9, 0]);
    expect(done).toEqual({ a: 'eos', b: 'eos', c: 'eos' });
    expect(sched.freeLanes()).toBe(3);
  });

  it('TRUE continuous: admits more sequences than lanes; freed lanes re-fill mid-run', async () => {
    const binding = new MockBinding();
    const sched = new ContinuousBatchScheduler(binding, VOCAB, 2); // only 2 lanes

    const out: Record<string, number[]> = {};
    const done: Record<string, string> = {};
    // four sequences, two lanes → two must wait and re-use freed lanes.
    sched.admit(seq('a', [7], out, done)); // 8,9,0  (short, frees its lane early)
    sched.admit(seq('b', [1], out, done)); // 2..9,0 (long)
    sched.admit(seq('c', [8], out, done)); // 9,0
    sched.admit(seq('d', [6], out, done)); // 7,8,9,0

    await sched.run();

    expect(out.a).toEqual([8, 9, 0]);
    expect(out.b).toEqual([2, 3, 4, 5, 6, 7, 8, 9, 0]);
    expect(out.c).toEqual([9, 0]);
    expect(out.d).toEqual([7, 8, 9, 0]);
    expect(done).toEqual({ a: 'eos', b: 'eos', c: 'eos', d: 'eos' });
    expect(sched.queueDepth()).toBe(0);
    expect(sched.freeLanes()).toBe(2);
    // Lane re-use happened: more resetLane calls than the 2 initial-fill (c and d re-filled).
    expect(binding.resets.length).toBe(4); // a,b,c,d each reset their lane on admission
  });

  it('retires at maxNewTokens when no stop token is hit', async () => {
    const sched = new ContinuousBatchScheduler(new MockBinding(), VOCAB, 1);
    const out: number[] = [];
    let reason = '';
    sched.admit({
      id: 'm',
      promptTokens: [2],
      maxNewTokens: 3,
      sample: argmax,
      isStop: () => false,
      onToken: (t) => {
        out.push(t);
      },
      onDone: (r) => {
        reason = r;
      },
    });
    await sched.run();
    expect(out).toEqual([3, 4, 5]);
    expect(reason).toBe('maxTokens');
  });
});
